import type { MutableRefObject } from 'react';

import { DEFAULT_SETTINGS, PROGRESS_BUTTON_STROKE_WIDTH } from './consts';
import type { SVGPathSettings } from './ProgressButton.types';

/** Рассчёт размеров контейнера и радиуса границ для отрисовки в нём svg */
export const calcSettings = (buttonRef: MutableRefObject<HTMLButtonElement>): SVGPathSettings => {
	const buttonObj = buttonRef?.current;

	if (buttonObj) {
		const buttonObjRect = buttonObj.getBoundingClientRect();
		return {
			width: buttonObjRect.width,
			height: buttonObjRect.height,
			startPos: buttonObj.offsetWidth / 2,
			strokeWidth: PROGRESS_BUTTON_STROKE_WIDTH,
			borderRadius: 12,
		};
	}

	return DEFAULT_SETTINGS;
};

export const calcPathDefinition = (settings: SVGPathSettings): string => `
	M ${settings.startPos} ${settings.strokeWidth} 
	H${settings.width - settings.borderRadius}
	a${settings.borderRadius},${settings.borderRadius} 0 0 1 ${settings.borderRadius},${settings.borderRadius}
	V${settings.height - settings.borderRadius}
	a${settings.borderRadius},${settings.borderRadius} 0 0 1 -${settings.borderRadius},${settings.borderRadius}
	H${settings.borderRadius + settings.strokeWidth}
	a${settings.borderRadius},${settings.borderRadius} 0 0 1 -${settings.borderRadius},-${settings.borderRadius}
	V${settings.borderRadius + settings.strokeWidth}
	a${settings.borderRadius},${settings.borderRadius} 0 0 1 ${settings.borderRadius},-${settings.borderRadius}
	H ${settings.startPos}
`;

/**
 * проверяет является ли переданный объект оьектом ошибки
 *
 * @param err потенциальный объект ошибки
 */
export const isErrorObject = (err): boolean =>
	!!err && typeof err === 'object' && Object.prototype.toString.call(err) === '[object Error]';
